local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("wing", function(inst, status)     TD.server(function()         if (status or TD.csv(inst):get("playerStatus")) == 4 then             inst.AnimState:OverrideSymbol("swap_body", TD.holder("swap_%s_wing"), "backpack")             inst.AnimState:OverrideSymbol("swap_body", TD.holder("swap_%s_wing"), "swap_body")         end     end) end) TD.createFn("wing2", function(inst, status)     TD.server(function()         inst.AnimState:OverrideSymbol("swap_body", TD.holder("swap_%s_wing"), "backpack")         inst.AnimState:OverrideSymbol("swap_body", TD.holder("swap_%s_wing"), "swap_body")     end) end) local bodySlots = {     _G.EQUIPSLOTS.BODY,     _G.EQUIPSLOTS.BACK,     _G.EQUIPSLOTS.NECK,     _G.EQUIPSLOTS.PACK } TD.createFn("withdrawWing", function(inst, status)     if (status or TD.csv(inst):get("playerStatus")) ~= 4 then         TD.fori(bodySlots, function(k, v)             if v ~= nil then                 TD.server(function()                     local equip = inst.components.inventory:GetEquippedItem(v)                     if equip ~= nil and equip.components.equippable and TD.isFn(equip.components.equippable.onequipfn) then                         equip.components.equippable.onequipfn(equip, inst)                         return true                     elseif inst and inst.AnimState and inst.AnimState.ClearOverrideSymbol then                         inst.AnimState:ClearOverrideSymbol("swap_body")                     end                 end)             end         end)     end end) TD.createFn("status2Tag", function(status)     if status == 1 then         return "q"     elseif status == 2 then         return "w"     elseif status == 3 then         return "e"     elseif status == 4 then         return "r"     end end) if not TD.G.td1madao_tkPrefabs then     TD.G.td1madao_tkPrefabs = {}     table.insert(TD.G.td1madao_tkPrefabs, "deidara2_dst_td1madao")     table.insert(TD.G.td1madao_tkPrefabs, "riven2_dst_td1madao")     table.insert(TD.G.td1madao_tkPrefabs, "yorha2b_dst_td1madao") end TD.createFn("getRandomTKPrefab", function(currentPrefab)     local weightMap = {}          TD.fori(TD.G.td1madao_tkPrefabs, function(k, v)         weightMap[v] = 1     end)          if TD.isStr(currentPrefab) and table.td1madao_contain(TD.G.td1madao_tkPrefabs,currentPrefab) then         TD.fori(TD.G.td1madao_tkPrefabs, function(k, v)                          if v~=currentPrefab then                 weightMap[v] = weightMap[v]*2             end         end)     end          TD.fori(TD.G.td1madao_tkPrefabs, function(k, v)                  if not _G.Prefabs[v] then             weightMap[v] = weightMap[v]*2         end     end)     local returnTable = {}     TD.fori(weightMap, function(k, v)         TD.fori(v, function()             table.insert(returnTable, k)         end)     end)     return TD.randomInTab(returnTable) end) TD.createFn("getTKPrefabName", function(currentPrefab)     if currentPrefab == "deidara2_dst_td1madao" then         return TD.showStr("迪达拉", "DEIDARA")     elseif currentPrefab == "riven2_dst_td1madao" then         return TD.showStr("锐雯", "RIVEN")     elseif currentPrefab == "yorha2b_dst_td1madao" then         return "2B"     end end) TD.createFn("getTKPrefabSkillName", function(currentPrefab,tag)     if currentPrefab == "deidara2_dst_td1madao" then         if tag == "q" then             return TD.showStr("起爆黏土·飞鸟", "explosive clay·bird")         elseif tag == "w" then             return TD.showStr("起爆黏土·蜘蛛", "explosive clay·spider")         elseif tag == "e" then             return TD.showStr("起爆黏土·猫头鹰", "explosive clay·giant bird")         elseif tag == "r" then             return TD.showStr("C3·18号", "C3·18th")         end     elseif currentPrefab == "riven2_dst_td1madao" then         if tag == "q" then             return TD.showStr("折翼之舞", "Broken Wings")         elseif tag == "w" then             return TD.showStr("镇魂怒吼", "Ki Burst")         elseif tag == "e" then             return TD.showStr("勇往直前", "Valor")         elseif tag == "r" then             return TD.showStr("放逐之锋", "Blade of the Exile")         end     elseif currentPrefab == "yorha2b_dst_td1madao" then         if tag == "q" then             return TD.showStr("空斩", "Empty-Cut")         elseif tag == "w" then             return TD.showStr("滑铲", "Slippers")         elseif tag == "e" then             return TD.showStr("反伤", "Anti-injury")         elseif tag == "r" then             return TD.showStr("光剑", "Light-sword")         end     end end) 